86	const defaultBaseURL = 'https://fal.run';
87	
88	function loadFalApiKey({
89	  apiKey,
90	  description = 'fal.ai',
91	}: {
92	  apiKey: string | undefined;
93	  description?: string;
94	}): string {
95	  if (typeof apiKey === 'string') {
96	    return apiKey;
97	  }
98	
99	  if (apiKey != null) {
100	    throw new Error(`${description} API key must be a string.`);
101	  }
102	
103	  if (typeof process === 'undefined') {
104	    throw new Error(
105	      `${description} API key is missing. Pass it using the 'apiKey' parameter. Environment variables are not supported in this environment.`,
106	    );
107	  }
108	
109	  let envApiKey = process.env.FAL_API_KEY;
110	  if (envApiKey == null) {
111	    envApiKey = process.env.FAL_KEY;
112	  }
113	
114	  if (envApiKey == null) {
115	    throw new Error(
116	      `${description} API key is missing. Pass it using the 'apiKey' parameter or set either the FAL_API_KEY or FAL_KEY environment variable.`,
117	    );
118	  }
119	
120	  if (typeof envApiKey !== 'string') {
121	    throw new Error(
122	      `${description} API key must be a string. The value of the environment variable is not a string.`,
123	    );
124	  }
125	
126	  return envApiKey;
127	}
