42	/**
43	 * Generates images using an image model.
44	 *
45	 * @param model - The image model to use.
46	 * @param prompt - The prompt that should be used to generate the image.
47	 * @param n - Number of images to generate. Default: 1.
48	 * @param maxImagesPerCall - Maximum number of images to generate in a single API call.
49	 * @param size - Size of the images to generate. Must have the format `{width}x{height}`.
50	 * @param aspectRatio - Aspect ratio of the images to generate. Must have the format `{width}:{height}`.
51	 * @param seed - Seed for the image generation.
52	 * @param providerOptions - Additional provider-specific options that are passed through to the provider
53	 * as body parameters.
54	 * @param maxRetries - Maximum number of retries. Set to 0 to disable retries. Default: 2.
55	 * @param abortSignal - An optional abort signal that can be used to cancel the call.
56	 * @param headers - Additional HTTP headers to be sent with the request. Only applicable for HTTP-based providers.
57	 *
58	 * @returns A result object that contains the generated images.
59	 */
60	export async function generateImage({
61	  model: modelArg,
62	  prompt: promptArg,
63	  n = 1,
64	  maxImagesPerCall,
65	  size,
66	  aspectRatio,
67	  seed,
68	  providerOptions,
69	  maxRetries: maxRetriesArg,
70	  abortSignal,
71	  headers,
72	}: {
73	  /**
