export function createFal(options: FalProviderSettings = {}): FalProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
  const getHeaders = () => 
    withUserAgentSuffix({
      Authorization: `Key ${loadFalApiKey({ apiKey: options.apiKey })}`,
      ...options.headers,
    }, `ai-sdk/fal/${VERSION}`);

  const createImageModel = (modelId: FalImageModelId) =>
    new FalImageModel(modelId, {
      provider: 'fal.image',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  return {
    specificationVersion: 'v3',
    imageModel: createImageModel,
    image: createImageModel,
    // ... other model factories
  };
}

export const fal = createFal();
```

### 8. Image Model Implementation Pattern

**Key interface from ImageModelV3:**
```typescript
export class FalImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider(): string { return this.config.provider; }

  async doGenerate(options: Parameters<ImageModelV3['doGenerate']>[0]): Promise<...> {
    const { requestBody, warnings } = await this.getArgs(options);

    // Make API request
    const { value, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/${this.modelId}`,
      headers: combineHeaders(...),
      body: requestBody,
      failedResponseHandler: ...,
      successfulResponseHandler: createJsonResponseHandler(...),
      abortSignal: options.abortSignal,
      fetch: this.config.fetch,
    });

    // Download images
    const downloadedImages = await Promise.all(
      targetImages.map(image =>
        this.downloadImage(image.url, options.abortSignal)
      )
    );

    return {
      images: downloadedImages,
      warnings,
      response: { modelId, timestamp, headers },
      providerMetadata: { fal: {...} },
    };
  }
}
```

**Image generation flow:**
1. Parse/validate `providerOptions` using zod schemas
2. Build request body (prompt, size, seed, etc.)
3. Handle file input (convert to data URIs or base64)
4. Make API call using `postJsonToApi` with response handlers
5. Download generated images from URLs
6. Return images as Uint8Array with metadata

