### 10. `packages/pixelart/src/pixelart-image-options.ts`

Defines the provider-specific options validated with Zod. Uses `lazySchema` + `zodSchema` + `InferSchema` pattern from `@ai-sdk/provider-utils`.

The `style` and `pixelDensity` fields are provider-specific (not part of the standard `ImageModelV3CallOptions`), so they live here as `providerOptions.pixelart.*`.

```typescript
import { InferSchema, lazySchema, zodSchema } from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * Visual style of the generated pixel art.
       * - 'pixel': Classic pixel art aesthetic
       * - 'retro': Retro gaming aesthetic
       * - '8bit': 8-bit video game aesthetic
       */
      style: z.enum(['pixel', 'retro', '8bit']).optional(),
      /**
       * Pixel density of the output image (pixels per unit).
       * Higher values produce more detailed pixel art. Range: 1–16.
       */
      pixelDensity: z.number().min(1).max(16).optional(),
    }).passthrough(),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;
```

### 11. `packages/pixelart/src/pixelart-image-model.ts`

Implements the `ImageModelV3` interface. Key implementation decisions:
- The fictional API endpoint: `POST https://api.pixelart.ai/v1/images/generate`
- Standard options (`prompt`, `n`, `size`, `seed`) map to request body fields directly
- Provider-specific options (`style`, `pixelDensity`) are parsed from `providerOptions.pixelart` and added to the request body as `style` and `pixel_density`
- The API returns a JSON response with a `data` array of objects containing a `url` field
- Images are downloaded as binary `Uint8Array` using `getFromApi` + `createBinaryResponseHandler`
- Error responses have `{ error: { message: string, type: string } }` shape

```typescript
import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createBinaryResponseHandler,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  createStatusCodeErrorResponseHandler,
  FetchFunction,
  getFromApi,
  parseProviderOptions,
  postJsonToApi,
  resolve,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import type { PixelArtImageModelId } from './pixelart-image-settings';
import { pixelArtImageModelOptionsSchema } from './pixelart-image-options';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

// Response schema for successful image generation
const pixelArtImageResponseSchema = z.object({
  id: z.string().nullish(),
  created: z.number().nullish(),
  data: z.array(
    z.object({
      url: z.string(),
      style: z.string().nullish(),
      pixel_density: z.number().nullish(),
    }),
  ),
});

// Error schema
const pixelArtErrorSchema = z.object({
  error: z.object({
    message: z.string(),
    type: z.string().nullish(),
  }),
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: error => error.error.message,
});

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  private async getArgs({
    prompt,
    n,
    size,
    seed,
    providerOptions,
  }: Parameters<ImageModelV3['doGenerate']>[0]) {
    const warnings: Array<SharedV3Warning> = [];

    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const requestBody: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
      seed,
    };

    if (size != null) {
      requestBody.size = size;
    }

    if (pixelArtOptions?.style != null) {
      requestBody.style = pixelArtOptions.style;
    }

    if (pixelArtOptions?.pixelDensity != null) {
      requestBody.pixel_density = pixelArtOptions.pixelDensity;
    }

    return { requestBody, warnings } as const;
  }

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const { requestBody, warnings } = await this.getArgs(options);

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(
        await resolve(this.config.headers),
        options.headers,
      ),
      body: requestBody,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      abortSignal: options.abortSignal,
      fetch: this.config.fetch,
    });

    // Download all images from returned URLs
    const downloadedImages = await Promise.all(
      value.data.map(item =>
        this.downloadImage(item.url, options.abortSignal),
      ),
    );

    return {
      images: downloadedImages,
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          id: value.id ?? null,
          created: value.created ?? null,
          images: value.data.map(item => ({
            style: item.style ?? null,
            pixelDensity: item.pixel_density ?? null,
          })),
        },
      },
    };
  }

  private async downloadImage(
    url: string,
    abortSignal: AbortSignal | undefined,
  ): Promise<Uint8Array> {
    const { value: response } = await getFromApi({
      url,
      abortSignal,
      failedResponseHandler: createStatusCodeErrorResponseHandler(),
      successfulResponseHandler: createBinaryResponseHandler(),
      fetch: this.config.fetch,
    });
    return response;
  }
}
```

### 12. `packages/pixelart/src/pixelart-provider.ts`

Implements the factory function and provider interface. Since PixelArt only supports image generation, all other model type methods throw `NoSuchModelError`.

```typescript
import { ImageModelV3, NoSuchModelError, ProviderV3 } from '@ai-sdk/provider';
import type { FetchFunction } from '@ai-sdk/provider-utils';
import {
  loadApiKey,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import type { PixelArtImageModelId } from './pixelart-image-settings';
import { VERSION } from './version';

const defaultBaseURL = 'https://api.pixelart.ai/v1';

export interface PixelArtProviderSettings {
  /**
   * PixelArt API key. Defaults to the PIXELART_API_KEY environment variable.
   */
  apiKey?: string;
  /**
   * Base URL for API calls. Defaults to https://api.pixelart.ai/v1.
   */
  baseURL?: string;
  /**
   * Custom headers to include in every request.
   */
  headers?: Record<string, string>;
  /**
   * Custom fetch implementation for middleware/testing.
   */
  fetch?: FetchFunction;
}

export interface PixelArtProvider extends ProviderV3 {
  /**
   * Creates an image generation model.
   */
  image(modelId: PixelArtImageModelId): ImageModelV3;
  /**
   * Creates an image generation model.
   */
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
}

export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL =
    withoutTrailingSlash(options.baseURL ?? defaultBaseURL) ?? defaultBaseURL;

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  return {
    specificationVersion: 'v3' as const,
    image: createImageModel,
    imageModel: createImageModel,
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
    },
    embeddingModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
    },
  };
}

/**
 * Default PixelArt provider instance.
 */
export const pixelArt = createPixelArt();
```

